function Hello() {
  return <h1>Hello, world!</h1>;
}

export default Hello;

import Hello from './Hello';

function App() {
  return (
    <div>
      <Hello />
      <Hello />
    </div>
  );
}

// Receive the whole object
function Greeting(props) {
  return <h1>Hello, {props.name}!</h1>;
}

// Destructure inline — preferred for clarity
function Greeting({ name, age }) {
  return <h1>Hello, {name}! You are {age} years old.</h1>;
}

// Usage — attributes become props
<Greeting name="Alice" age={30} />

// WRONG — two root elements
function Bad() {
  return (
    <h1>Title</h1>
    <p>Paragraph</p>  // SyntaxError
  );
}

// OK — wrapped in a div
function Wrapped() {
  return (
    <div>
      <h1>Title</h1>
      <p>Paragraph</p>
    </div>
  );
}

// OK — Fragment (no extra DOM node)
function Fragmented() {
  return (
    <>
      <h1>Title</h1>
      <p>Paragraph</p>
    </>
  );
}

// OK — renders nothing
function Hidden({ show }) {
  if (!show) return null;
  return <p>Visible!</p>;
}

function UserCard({ name, isAdmin, score, tags }) {
  return (
    <div>
      <h2>{name.toUpperCase()}</h2>           {/* method call */}
      <p>Score: {score * 100}%</p>            {/* arithmetic */}
      {isAdmin && <span>Admin</span>}         {/* conditional */}
      {isAdmin ? <span>Admin</span> : null}   {/* ternary */}
      <ul>
        {tags.map(t => <li key={t}>{t}</li>)} {/* array map */}
      </ul>
    </div>
  );
}

// function declaration
function Greeting({ name }) {
  return <h1>Hello, {name}!</h1>;
}

// arrow function expression
const Greeting = ({ name }) => {
  return <h1>Hello, {name}!</h1>;
};

// arrow function with implicit return (JSX must be wrapped in parens)
const Greeting = ({ name }) => (
  <h1>Hello, {name}!</h1>
);

// All three export the same component; choose a style and be consistent

function Button({ label, variant = 'primary', disabled = false, onClick }) {
  return (
    <button
      className={`btn btn-${variant}`}
      disabled={disabled}
      onClick={onClick}
    >
      {label}
    </button>
  );
}

// Caller can omit any defaulted prop:
<Button label="Save" />                     // variant='primary', disabled=false
<Button label="Delete" variant="danger" />   // disabled=false
<Button label="Submit" disabled />           // disabled=true (boolean prop)

function Card({ title, children }) {
  return (
    <div className="card">
      <h2 className="card-title">{title}</h2>
      <div className="card-body">{children}</div>
    </div>
  );
}

// Usage — anything between the tags becomes children
<Card title="Welcome">
  <p>This is the card body.</p>
  <button>Click me</button>
</Card>

// Greeting.jsx

// Named export — can have many per file
export function Greeting({ name }) {
  return <h1>Hello, {name}!</h1>;
}

// Default export — one per file
export default function App() {
  return <Greeting name="world" />;
}

// ------------------------------------------------
// In another file:
import App from './App';             // default import
import { Greeting } from './App';    // named import
import App, { Greeting } from './App'; // both

function Avatar({ src, alt }) {
  return <img className="avatar" src={src} alt={alt} />;
}

function UserInfo({ name, role, avatarSrc }) {
  return (
    <div className="user-info">
      <Avatar src={avatarSrc} alt={name} />
      <div>
        <strong>{name}</strong>
        <span>{role}</span>
      </div>
    </div>
  );
}

function ProfileCard({ user }) {
  return (
    <div className="card">
      <UserInfo
        name={user.name}
        role={user.role}
        avatarSrc={user.avatar}
      />
    </div>
  );
}

// Greeting.jsx
function Greeting({ name }) {  // no export!
  return <h1>Hello, {name}!</h1>;
}

// App.jsx
import Greeting from './Greeting'; // SyntaxError: no default export
// Fix: add `export default` to the function, or `export { Greeting }`

// WRONG — bypasses React's rendering system
function App() {
  return <div>{Greeting({ name: 'Alice' })}</div>; // direct function call
}

// Correct — let React manage the instance
function App() {
  return <div><Greeting name="Alice" /></div>;
}

// WRONG
function Profile() {
  return (
    <h1>Name</h1>    // error: JSX expressions must have one parent element
    <p>Bio</p>
  );
}

// Fix with Fragment
function Profile() {
  return (
    <>
      <h1>Name</h1>
      <p>Bio</p>
    </>
  );
}

// WRONG — props are read-only
function BadGreeting({ name }) {
  name = name.toUpperCase(); // mutating the prop
  return <h1>{name}</h1>;
}

// Correct — derive a new value
function GoodGreeting({ name }) {
  const displayName = name.toUpperCase(); // local variable
  return <h1>{displayName}</h1>;
}

function StatusBadge({ status, isVerified }) {
  // 1. Early return — entire component conditionally renders
  if (status === 'banned') return null;

  return (
    <div className="badge">
      {/* 2. Ternary — two outcomes */}
      <span>{status === 'active' ? '🟢 Active' : '🔴 Inactive'}</span>

      {/* 3. Logical AND — one outcome or nothing */}
      {isVerified && <span className="check">✓ Verified</span>}
    </div>
  );
}

function TodoList({ todos }) {
  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id} className={todo.done ? 'done' : ''}>
          {todo.text}
        </li>
      ))}
    </ul>
  );
}

// Keys must be unique among siblings, stable (not random), and
// ideally from the data (database IDs). Avoid array index as key
// unless the list is static and never reordered.

// className — references a CSS class defined in a stylesheet
<div className="card highlighted">...</div>

// Inline style — JS object, not a string
<div style={{ color: 'red', fontSize: 16, marginTop: '8px' }}>...</div>

// Dynamic className (common pattern)
function Alert({ type, message }) {
  return (
    <div className={`alert alert-${type}`}>
      {message}
    </div>
  );
}

// ProductCard.jsx
export function ProductBadge({ label, variant = 'default' }) {
  return (
    <span className={`badge badge-${variant}`}>{label}</span>
  );
}

export default function ProductCard({
  name,
  price,
  imageUrl,
  tags = [],
  inStock = true,
  onAddToCart,
}) {
  return (
    <div className="product-card">
      <img src={imageUrl} alt={name} className="product-image" />

      <div className="product-info">
        <h3>{name}</h3>
        <p className="price">${price.toFixed(2)}</p>

        {/* Render tags if any */}
        {tags.length > 0 && (
          <div className="tags">
            {tags.map(tag => (
              <ProductBadge key={tag} label={tag} />
            ))}
          </div>
        )}

        {/* Conditional stock status */}
        {!inStock && (
          <ProductBadge label="Out of stock" variant="danger" />
        )}

        <button
          onClick={onAddToCart}
          disabled={!inStock}
          className="btn btn-primary"
        >
          Add to cart
        </button>
      </div>
    </div>
  );
}
